def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        multiplier = 1.0
        for p in range(1, 10):
            temp_sum = 0
            for q in range(1, p + 1):
                sign = (-1) ** (q + p)
                base = (ratio ** q) / (q ** 1.5)
                temp_sum += sign * base
            score += temp_sum * (0.9 + 0.1 * (p % 2))
        for threshold_percentage in [0.05, 0.15, 0.25, 0.35, 0.5]:
            threshold = threshold_percentage * capacity
            remaining = capacity - item
            if remaining < threshold:
                multiplier += (0.1 * (1.0 / threshold_percentage)) * (1 if threshold_percentage < 0.3 else -1)
        score *= max(multiplier, 0.1)
        mods = [int(capacity) % divisor == 0 for divisor in [4,6,9,11]]
        mod_scores = [0.1, -0.08, 0.07, -0.05]
        for flag, mod_score in zip(mods, mod_scores):
            if flag:
                score += mod_score * (capacity / 20)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < threshold / 2:
                penalty += 0.3 * k
            elif diff < threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.07 * k
            if k % 2 == 0 and (int(capacity) + k) % 5 == 0:
                penalty *= 1.05
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                cond_val = capacity / (m + 1)
                if abs(cond_val - item) < 0.015 * cond_val:
                    score *= (1 + 0.07 * m)
                elif abs(cond_val - item) < 0.03 * cond_val and m % 2 == 1:
                    score *= (1 + 0.03 * m)
        if np.isclose(ratio, 0.5, atol=0.02):
            score *= 1.2
        if capacity > 1000:
            score *= 0.85
        elif capacity < 50:
            score *= 1.15
        priorities[i] = score
    return priorities
